package com.example.api.service;

import com.example.api.exception.ResourceNotFoundException;
import com.example.api.model.Product;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import jakarta.annotation.PostConstruct;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class ProductService {

    private static final Logger logger = LoggerFactory.getLogger(ProductService.class);

    private final Map<Long, Product> productStore = new ConcurrentHashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(0);

    @PostConstruct
    public void init() {
        logger.info("Initializing ProductService with sample data");
        createProduct(new Product(null, "Laptop", "High-performance laptop", 1299.99));
        createProduct(new Product(null, "Keyboard", "Mechanical keyboard", 149.99));
        createProduct(new Product(null, "Monitor", "4K Ultra HD monitor", 499.99));
        logger.info("ProductService initialized with {} products", productStore.size());
    }

    public List<Product> getAllProducts() {
        logger.info("Retrieving all products");
        List<Product> products = new ArrayList<>(productStore.values());
        logger.info("Retrieved {} products successfully", products.size());
        return products;
    }

    public Product getProductById(Long id) {
        logger.info("Retrieving product with id={}", id);
        Product product = productStore.get(id);
        if (product == null) {
            logger.warn("Product with id={} not found", id);
            throw new ResourceNotFoundException("Product not found with id: " + id);
        }
        logger.info("Product retrieved successfully: {}", product);
        return product;
    }

    public Product createProduct(Product product) {
        Long id = idGenerator.incrementAndGet();
        product.setId(id);
        logger.info("Creating new product with id={}, name='{}'", id, product.getName());
        productStore.put(id, product);
        logger.info("Product created successfully: {}", product);
        return product;
    }

    public Product updateProduct(Long id, Product updatedProduct) {
        logger.info("Updating product with id={}", id);
        if (!productStore.containsKey(id)) {
            logger.warn("Cannot update - product with id={} not found", id);
            throw new ResourceNotFoundException("Product not found with id: " + id);
        }
        updatedProduct.setId(id);
        productStore.put(id, updatedProduct);
        logger.info("Product updated successfully: {}", updatedProduct);
        return updatedProduct;
    }

    public void deleteProduct(Long id) {
        logger.info("Deleting product with id={}", id);
        if (!productStore.containsKey(id)) {
            logger.warn("Cannot delete - product with id={} not found", id);
            throw new ResourceNotFoundException("Product not found with id: " + id);
        }
        Product removed = productStore.remove(id);
        logger.info("Product deleted successfully: {}", removed);
    }

    public List<Product> searchProducts(String name) {
        logger.info("Searching products with name containing '{}'", name);
        List<Product> results = productStore.values().stream()
                .filter(p -> p.getName().toLowerCase().contains(name.toLowerCase()))
                .toList();
        logger.info("Search completed - found {} products matching '{}'", results.size(), name);
        return results;
    }
}

