package com.example.api.controller;

import com.example.api.model.ApiResponse;
import com.example.api.model.Product;
import com.example.api.service.ProductService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/v1/products")
public class ProductController {

    private static final Logger logger = LoggerFactory.getLogger(ProductController.class);

    private final ProductService productService;

    public ProductController(ProductService productService) {
        this.productService = productService;
        logger.info("ProductController initialized");
    }

    @GetMapping
    public ResponseEntity<ApiResponse<List<Product>>> getAllProducts() {
        logger.info("GET /api/v1/products - Fetching all products");
        List<Product> products = productService.getAllProducts();
        ApiResponse<List<Product>> response = new ApiResponse<>(true, "Products retrieved successfully", products);
        logger.info("GET /api/v1/products - Returning {} products", products.size());
        return ResponseEntity.ok(response);
    }

    @GetMapping("/{id}")
    public ResponseEntity<ApiResponse<Product>> getProductById(@PathVariable Long id) {
        logger.info("GET /api/v1/products/{} - Fetching product by id", id);
        Product product = productService.getProductById(id);
        ApiResponse<Product> response = new ApiResponse<>(true, "Product retrieved successfully", product);
        logger.info("GET /api/v1/products/{} - Product found: {}", id, product.getName());
        return ResponseEntity.ok(response);
    }

    @PostMapping
    public ResponseEntity<ApiResponse<Product>> createProduct(@RequestBody Product product) {
        logger.info("POST /api/v1/products - Creating new product: name='{}'", product.getName());
        Product createdProduct = productService.createProduct(product);
        ApiResponse<Product> response = new ApiResponse<>(true, "Product created successfully", createdProduct);
        logger.info("POST /api/v1/products - Product created with id={}", createdProduct.getId());
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    @PutMapping("/{id}")
    public ResponseEntity<ApiResponse<Product>> updateProduct(@PathVariable Long id, @RequestBody Product product) {
        logger.info("PUT /api/v1/products/{} - Updating product", id);
        Product updatedProduct = productService.updateProduct(id, product);
        ApiResponse<Product> response = new ApiResponse<>(true, "Product updated successfully", updatedProduct);
        logger.info("PUT /api/v1/products/{} - Product updated successfully", id);
        return ResponseEntity.ok(response);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<ApiResponse<Void>> deleteProduct(@PathVariable Long id) {
        logger.info("DELETE /api/v1/products/{} - Deleting product", id);
        productService.deleteProduct(id);
        ApiResponse<Void> response = new ApiResponse<>(true, "Product deleted successfully", null);
        logger.info("DELETE /api/v1/products/{} - Product deleted successfully", id);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/search")
    public ResponseEntity<ApiResponse<List<Product>>> searchProducts(@RequestParam String name) {
        logger.info("GET /api/v1/products/search?name={} - Searching products", name);
        List<Product> products = productService.searchProducts(name);
        ApiResponse<List<Product>> response = new ApiResponse<>(true, "Search completed successfully", products);
        logger.info("GET /api/v1/products/search - Found {} results for '{}'", products.size(), name);
        return ResponseEntity.ok(response);
    }
}

